query:
SELECT pv.id, pv.variantCode, pv.variantName, pv.supplierId, pv.supplierSku, pv.customerId, pv.customerSku
FROM product_variants pv ORDER BY pv.id DESC LIMIT 1;

SELECT vm.variantId, vm.materialId, vm.colorCode FROM variant_materials vm WHERE vm.variantId = (SELECT MAX(id) FROM product_variants);

SELECT pb.variantId, pb.length, pb.width, pb.height, pb.cbm, pb.grossWeight, pb.netWeight FROM package_boxes pb WHERE pb.variantId = (SELECT MAX(id) FROM product_variants);

SELECT vcl.variantId, vcl.customerId FROM variant_customer_links vcl WHERE vcl.variantId = (SELECT MAX(id) FROM product_variants);

